external_knowledge:
; 'winning bets' refers to bets with an outcome of 'win'; 
; 'total winnings' is the sum of payout amounts for winning bets; 
; 'top 10 users with the highest total winnings' refers to users with the highest total winnings in descending order, limited to 10 users.

sql:
SELECT COUNT(selection_id) AS win_count
FROM selections
WHERE win_lose = 1;
